Two parallel async flows: `setInterval` for the blink, an async-iterable subscription for the pot. Pin 'A0' on the proxy puts the read in analog mode automatically.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'
import { ConduytServo } from 'conduyt-js/modules/servo'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

const servo = new ConduytServo(device)
await servo.attach(9)

await device.pin(13).mode('output')
let ledState = 0
setInterval(async () => {
  ledState ^= 1
  await device.pin(13).write(ledState)
}, 1500)

for await (const raw of device.pin('A0').subscribe({ intervalMs: 50 })) {
  await servo.write(Math.round((raw / 1023) * 180))
}
```

