Wrap any transport in `ReconnectTransport` and use the wrapper in `connect`. The `onReconnect` setter fires after each successful re-establish, where you can re-arm any subscriptions that the firmware drops on disconnect.

```ts
import { ConduytDevice, ReconnectTransport } from 'conduyt-js'
import { BLETransport } from 'conduyt-js/transports/ble'

document.querySelector<HTMLButtonElement>('#connect')!.addEventListener('click', async () => {
  const transport = new ReconnectTransport(
    new BLETransport(),
    { initialDelay: 500, maxDelay: 10000 }
  )
  transport.onReconnect = () => {
    console.log('ble reconnected')
  }

  const device = await ConduytDevice.connect(transport)
  await device.ping()
})
```

