`MockTransport` is in-memory but doesn't auto-respond. `ConduytDevice.connect()` awaits a HELLO_RESP, so you have to wrap `transport.send` to inject one. The conduyt-js test suite does this in `sdk/js/test/device.test.ts`.

```ts
import { ConduytDevice, EVT, CMD, makePacket, wireEncode, wireDecode } from 'conduyt-js'
import { MockTransport } from 'conduyt-js/transports/mock'

function helloPayload(): Uint8Array {
  const buf: number[] = []
  const pad = (s: string, n: number) => {
    const b = new TextEncoder().encode(s)
    for (let i = 0; i < n; i++) buf.push(i < b.length ? b[i] : 0)
  }
  pad('Mock', 16); buf.push(1, 0, 0)
  for (let i = 0; i < 8; i++) buf.push(0)
  buf.push(0, 20)
  for (let i = 0; i < 20; i++) buf.push(0x0F)
  buf.push(1, 1, 1, 0x00, 0x02, 0, 0)
  return new Uint8Array(buf)
}

function autoRespond(t: MockTransport): void {
  const orig = t.send.bind(t)
  t.send = async (packet: Uint8Array) => {
    await orig(packet)
    const { type, seq } = wireDecode(packet)
    if (type === CMD.HELLO) {
      t.inject(wireEncode(makePacket(EVT.HELLO_RESP, seq, helloPayload())))
    } else {
      t.inject(wireEncode(makePacket(EVT.ACK, seq)))
    }
  }
}

const transport = new MockTransport()
autoRespond(transport)
const device = await ConduytDevice.connect(transport)
console.log('connected =', device.connected)
```

Wrap the same `autoRespond` helper inside a vitest spec. `clearSent()` zeros the buffer after the connect handshake so the assertion only sees the test commands.

```ts
import { describe, it, expect } from 'vitest'
import { ConduytDevice, EVT, CMD, makePacket, wireEncode, wireDecode } from 'conduyt-js'
import { MockTransport } from 'conduyt-js/transports/mock'

function helloPayload(): Uint8Array {
  const buf: number[] = []
  const pad = (s: string, n: number) => {
    const b = new TextEncoder().encode(s)
    for (let i = 0; i < n; i++) buf.push(i < b.length ? b[i] : 0)
  }
  pad('Mock', 16); buf.push(1, 0, 0)
  for (let i = 0; i < 8; i++) buf.push(0)
  buf.push(0, 20)
  for (let i = 0; i < 20; i++) buf.push(0x0F)
  buf.push(1, 1, 1, 0x00, 0x02, 0, 0)
  return new Uint8Array(buf)
}

function autoRespond(t: MockTransport): void {
  const orig = t.send.bind(t)
  t.send = async (packet: Uint8Array) => {
    await orig(packet)
    const { type, seq } = wireDecode(packet)
    if (type === CMD.HELLO) {
      t.inject(wireEncode(makePacket(EVT.HELLO_RESP, seq, helloPayload())))
    } else {
      t.inject(wireEncode(makePacket(EVT.ACK, seq)))
    }
  }
}

describe('pin mode', () => {
  it('sends one packet for mode(output)', async () => {
    const transport = new MockTransport()
    autoRespond(transport)
    const device = await ConduytDevice.connect(transport)
    transport.clearSent()

    await device.pin(13).mode('output')

    expect(transport.sentPackets.length).toBe(1)
  })
})
```

