Track the latest value per pin in a shared object. Emit a CSV line only after both have produced at least one reading.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

const latest: Record<string, number | null> = { A0: null, A1: null }

const run = (name: 'A0' | 'A1') => (async () => {
  for await (const v of device.pin(name).subscribe({ intervalMs: 100 })) {
    latest[name] = v
    if (latest.A0 !== null && latest.A1 !== null) {
      console.log(`${latest.A0},${latest.A1}`)
    }
  }
