await Promise.all([run('A0'), run('A1')])
```

Linear interpolation across frames. ~50 frames at 40 ms each gives a smooth ramp without flooding the wire.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'
import { ConduytNeoPixel } from 'conduyt-js/modules/neopixel'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

const pixels = new ConduytNeoPixel(device)
await pixels.begin(5, 30)

const FRAMES = 50
for (let i = 0; i <= FRAMES; i++) {
  const t = i / FRAMES
  const r = Math.round(255 * (1 - t))
  const g = Math.round(255 * t)
  await pixels.fill(r, g, 0)
  await pixels.show()
  await new Promise((r) => setTimeout(r, 40))
}
```

Push each reading; trim the buffer to keep the chart bounded.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'
import { ConduytDHT } from 'conduyt-js/modules/dht'
import { Chart } from 'chart.js/auto'

const chart = new Chart(document.querySelector<HTMLCanvasElement>('#c')!, {
  type: 'line',
  data: { labels: [], datasets: [{ label: 'T', data: [] }] },
  options: { animation: false },
})

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)
const dht = new ConduytDHT(device)
await dht.begin(4, 22)

const MAX_POINTS = 60
for (let i = 0; ; i++) {
  const { temperature } = await dht.read()
  chart.data.labels!.push(String(i))
  chart.data.datasets[0].data.push(temperature)
  if (chart.data.labels!.length > MAX_POINTS) {
    chart.data.labels!.shift()
    chart.data.datasets[0].data.shift()
  }
  chart.update('none')
  await new Promise((r) => setTimeout(r, 10000))
}
```

Wrap `device.ping()` with `Promise.race` against a setTimeout-based timeout.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

async function pingWithTimeout(ms: number) {
  return Promise.race([
    device.ping(),
    new Promise((_, reject) =>
      setTimeout(() => reject(new Error(`ping timeout after ${ms}ms`)), ms)
    ),
  ])
}

setInterval(async () => {
  try {
    await pingWithTimeout(1000)
  } catch (e) {
    console.warn('heartbeat:', (e as Error).message)
  }
}, 5000)
```

