Use `readline.createInterface` on stdin; parse each line. Skip non-numeric lines.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'
import { ConduytPID } from 'conduyt-js/modules/pid'
import readline from 'node:readline'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)
const pid = new ConduytPID(device)
await pid.config(1.0, 0.1, 0.05)
await pid.setInput(14)
await pid.setOutput(9)
await pid.setTarget(25.0)
await pid.enable()

const rl = readline.createInterface({ input: process.stdin })
rl.on('line', async (line) => {
  const v = parseFloat(line.trim())
  if (!Number.isNaN(v)) {
    await pid.setTarget(v)
