Track the timestamp of the last accepted reading; ignore readings that arrive within the debounce window.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

const DEBOUNCE_MS = 100
let lastEmit = 0
for await (const v of device.pin('A0').subscribe({ intervalMs: 50, threshold: 10 })) {
  const now = Date.now()
  if (now - lastEmit < DEBOUNCE_MS) continue
  lastEmit = now
  console.log(v)
}
```

