There's no global pause; you have to gate your own operations with a flag the application checks. The pattern below sets a flag, halts other code paths, then clears it after the flash.

```ts
import { ConduytDevice, ConduytOTA } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

let flashing = false

async function safeWrite(pin: number, value: number) {
  if (flashing) return
  await device.pin(pin).write(value)
}

declare const firmware: Uint8Array

try {
  flashing = true
  const ota = new ConduytOTA(device)
  await ota.flash(firmware, {
    onProgress: (sent, total) => console.log(`OTA ${(sent / total * 100).toFixed(1)}%`),
  })
} finally {
  flashing = false
}
```

