Two parallel async flows. The ramp loop writes; the subscribe loop reads. They share `device` but operate independently.

```ts
import { ConduytDevice } from 'conduyt-js'
import { SerialTransport } from 'conduyt-js/transports/serial'

const device = await ConduytDevice.connect(
  new SerialTransport({ path: '/dev/ttyACM0' })
)

const ramp = (async () => {
  const STEPS = 30
  for (let i = 0; i <= STEPS; i++) {
    const target = Math.round((i / STEPS) * 1000)
    await device.datastream('target_speed').write(target)
    await new Promise((r) => setTimeout(r, 1000))
  }
})()

const monitor = (async () => {
  for await (const v of device.datastream('speed').subscribe()) {
    console.log('speed =', v)
  }
})()

await Promise.all([ramp, monitor])
```

